// =====================================================
// Coastal Kingdom — a composed scene.
// Reads west → east:  sea ┬ beach ┬ pier ┬ town ┬ castle ┬ forest.
// One focal point (the Castle), everything else supports it.
// =====================================================

import "buildings.map";

part SmallPlaza {
  size 3, 3;
  fill STONE from (0,0) to (2,2);
  tile TORCH at (1,1);
}

map CoastalKingdom {
  size 36, 22;

  // ─── The sea (animated) ───
  fill WATER from (0,0) to (2,21);

  // ─── Sandy beach ───
  fill SAND from (3,0) to (4,21);

  // ─── Wooden pier reaching out from the beach ───
  tile WOOD at (3,10);
  tile WOOD at (4,10);
  tile WOOD at (3,11);
  tile WOOD at (4,11);
  tile WOOD at (3,12);
  tile WOOD at (4,12);
  tile TORCH at (3,9);
  tile TORCH at (4,9);

  // ─── Stone highway running east across the map ───
  row STONE from (5,12) to (33,12);
  row STONE from (5,13) to (33,13);

  // ─── Two cottages north of the road, doors opening onto it ───
  place Cottage at (5,7);     // door at world (7,11), (8,11)
  place Cottage at (11,7);    // door at world (13,11), (14,11)

  // ─── The castle, dominating the east half ───
  place Castle at (17,0);     // gate at world (24,11), (25,11)

  // ─── A small stone plaza off the south side of the road ───
  place SmallPlaza at (9,15);

  // ─── A deliberate forest clearing in the south-east, with a pond ───
  tile TREE_PINE at (17,16);
  tile TREE_OAK  at (19,18);
  tile TREE_PINE at (22,15);
  tile TREE_OAK  at (25,17);
  tile TREE_PINE at (28,16);
  tile TREE_OAK  at (31,18);
  tile TREE_PINE at (34,16);
  tile TREE_OAK  at (35,19);

  // The pond sits in the gap left between trees
  fill WATER from (27,19) to (29,21);
  tile ROCK at (27,19);

  // ─── Light decoration only — a handful of flowers, no scatter ───
  tile FLOWER at (5,16);
  tile FLOWER at (14,17);
  tile FLOWER at (35,11);

  // Player spawns at the seaward end of the pier.
  player at (3,10);
}
